import { forwardRef } from 'react';

import { iterateSeriesSlots } from './iterate-slots.js';
import { transformTimeseriesDataToXYChart } from './transformer-data-to-xy.js';
import {
  DEFAULT_VARIANT,
  type ChartVariantInternal,
  type TimeseriesChartProps,
  type TimeseriesChartRef,
} from './types/timeseries.js';
import {
  defineAxisId,
  renderAreaSeries,
  renderBandSeries,
  renderBarSeries,
  renderLineSeries,
  xAxisId,
} from './utils/render-series.js';
import { XYChart } from '../../xy-chart/XYChartRoot.js';

export const TimeseriesToXY = forwardRef<
  TimeseriesChartRef,
  TimeseriesChartProps
>((props, _ref) => {
  const { data = [], variant = DEFAULT_VARIANT, children } = props;

  const { line, bar, area, band, shapePriority } = iterateSeriesSlots(children);

  const buckets = {
    line: variant === 'line' ? [...data, ...line] : line,
    area: variant === 'area' ? [...data, ...area] : area,
    bar: variant === 'bar' ? [...data, ...bar] : bar,
    band,
  };

  const order: ChartVariantInternal[] = [...shapePriority];
  if (data.length > 0 && !order.includes(variant)) {
    order.push(variant);
  }

  const result = transformTimeseriesDataToXYChart(buckets, order);

  const seriesForShape = (shape: ChartVariantInternal) => {
    switch (shape) {
      case 'line':
        return result.line.map(renderLineSeries);
      case 'area':
        return result.area.map(renderAreaSeries);
      case 'bar':
        return result.bar.map(renderBarSeries);
      case 'band':
        return result.band.map(renderBandSeries);
    }
  };

  return (
    <XYChart data={[]}>
      {order.flatMap(seriesForShape)}
      <XYChart.XAxis
        id={xAxisId}
        type="time"
        position="bottom"
        // TimeseriesChart always spans the full data range on the time axis — there is no API to override it.
        min="data-min"
        max="data-max"
      />
      {[...result.units].map((unit, index) => (
        <XYChart.YAxis
          key={defineAxisId(unit)}
          id={defineAxisId(unit)}
          type="numerical"
          unit={unit}
          position={index % 2 === 0 ? 'left' : 'right'}
        />
      ))}
    </XYChart>
  );
});
